head.script:

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 */
scwin.initScreen = function() {
	if (scwin.initStatus) {
		if (typeof scwin.initScreen === "function") {
			scwin.initScreen();
		}

		if (typeof scwin.initContent === "function") {
			scwin.initContent();
		}
	}
};

scwin.initContent = function() {
	if (typeof parent.trv_LeftMenu !== "undefined") {
		tbx_ScreenTitle.setLabel(parent.trv_LeftMenu.getSelectedLabel());
	}
};
